public function execute(ApprovalInstance $instance): mixed
{
    return approve_scope($instance->id, function () use ($instance) {
        $action = app($instance->action_class_fqcn);
        $args = $this->hydratePayload($instance->payload_json);
        return $action(...$args);
    });
}

public function update(User $user, Invoice $invoice): bool
{
    if (approval_for($invoice) !== null) {
        return false;  // locked pending approval
    }
    return $user->can('invoices.update');
}
